import{_ as e,o as a,c as l,a0 as r}from"./chunks/framework.Bogozrur.js";const u=JSON.parse('{"title":"🦝 RAG 智能知识库","description":"","frontmatter":{},"headers":[],"relativePath":"projects/rag-knowledge-base.md","filePath":"projects/rag-knowledge-base.md"}'),i={name:"projects/rag-knowledge-base.md"};function n(o,t,s,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="🦝-rag-智能知识库" tabindex="-1">🦝 RAG 智能知识库 <a class="header-anchor" href="#🦝-rag-智能知识库" aria-label="Permalink to &quot;🦝 RAG 智能知识库&quot;">​</a></h1><blockquote><p>企业级知识库问答系统 · GitHub 开源</p></blockquote><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p>基于 LangChain + ChromaDB + Streamlit 构建的企业级 RAG 知识库问答系统。用户上传 PDF/Word/Markdown 文档后，AI 能基于文档内容进行智能问答，支持多轮对话、多知识库管理、混合检索等功能。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><ul><li><strong>多知识库管理</strong>：创建、切换、删除独立知识库</li><li><strong>多格式文档支持</strong>：PDF / TXT / MD / DOCX</li><li><strong>混合检索</strong>：向量检索 + BM25 关键词检索</li><li><strong>多模型接入</strong>：Ollama（本地）/ OpenAI / DeepSeek / 通义千问</li><li><strong>Agent 模式</strong>：AI 自动选择知识库检索、联网搜索或直接回答</li><li><strong>流式输出</strong>：文字逐字显示，无需等待完整生成</li><li><strong>RAG 模式与 Agent 模式</strong>：两种模式自由切换</li><li><strong>用户系统</strong>：登录注册、Session 管理、密码加密</li></ul><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:left;">技术</th></tr></thead><tbody><tr><td style="text-align:left;">前端</td><td style="text-align:left;">Streamlit · 自定义 CSS（浅蓝商务风）</td></tr><tr><td style="text-align:left;">后端</td><td style="text-align:left;">Python · LangChain · FastAPI</td></tr><tr><td style="text-align:left;">向量数据库</td><td style="text-align:left;">ChromaDB · BM25 混合检索</td></tr><tr><td style="text-align:left;">LLM</td><td style="text-align:left;">Ollama · OpenAI · DeepSeek · 通义千问</td></tr><tr><td style="text-align:left;">数据库</td><td style="text-align:left;">SQLAlchemy · SQLite</td></tr><tr><td style="text-align:left;">部署</td><td style="text-align:left;">Docker · Streamlit Cloud</td></tr></tbody></table><h2 id="安全特性" tabindex="-1">安全特性 <a class="header-anchor" href="#安全特性" aria-label="Permalink to &quot;安全特性&quot;">​</a></h2><ul><li>bcrypt 密码哈希</li><li>Session Token（BLAKE2b 签名）</li><li>登录速率限制（5 次失败锁定 15 分钟）</li><li>文件上传白名单校验</li><li>日志自动脱敏</li><li>XSS 防护 / CSRF 防护</li></ul><h2 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h2><ul><li>GitHub：<a href="https://github.com/nusireti/rag-knowledge-base" target="_blank" rel="noreferrer">https://github.com/nusireti/rag-knowledge-base</a></li></ul><h2 id="截图" tabindex="-1">截图 <a class="header-anchor" href="#截图" aria-label="Permalink to &quot;截图&quot;">​</a></h2><p><em>（待补充）</em></p>',14)])])}const b=e(i,[["render",n]]);export{u as __pageData,b as default};
